questions.explanation:
&lt;p&gt;सही उत्तर है - &amp;lsquo;&lt;strong&gt;वियोग&lt;/strong&gt;&amp;rsquo;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;lsquo;&lt;strong&gt;विप्रलंभ&lt;/strong&gt;&amp;rsquo; का आशय &amp;lsquo;&lt;strong&gt;वियोग&lt;/strong&gt;&amp;rsquo;&amp;nbsp;से है।&lt;/li&gt;
	&lt;li&gt;&amp;lsquo;&lt;strong&gt;विप्रलंभ&lt;/strong&gt;&amp;rsquo; का अर्थ :&amp;nbsp;प्रेमी प्रेमिका का वियोग।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&amp;nbsp;&lt;/span&gt;&lt;strong&gt;अन्य विकल्प:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;संयोग&lt;/strong&gt; :&amp;nbsp;मिलाप या&amp;nbsp;संग।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;महायोग &lt;/strong&gt;: यह&amp;nbsp;बज्रयान अन्तर्गत का एक तान्त्रिक संप्रदाय है। इस संप्रदाय ञिङमा संप्रदाय के नौ यान मध्ये सातवाँ यान है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;योग&lt;/strong&gt; : यह&amp;nbsp;आध्यात्मिक प्रक्रिया है जिसमें शरीर, मन और आत्मा को एक साथ लाने (योग) का काम होता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;योग &lt;/strong&gt;का अर्थ जुड़ना भी होता है।&amp;nbsp;यानी दो तत्वों का मिलन &lt;strong&gt;योग&lt;/strong&gt; कहलाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संयोग &lt;/strong&gt;को हम&lt;strong&gt;&amp;nbsp;इत्तेफाक&amp;nbsp;&lt;/strong&gt;भी कह सकते है यह&amp;nbsp;दो या कई बातों के अचानक एक साथ होने की क्रिया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&lt;u&gt;बल&lt;/u&gt;&lt;/strong&gt; संज्ञा शब्द में &lt;strong&gt;&amp;#39;वान&amp;#39; &lt;/strong&gt;प्रत्यय लगाने से नवीन विशेषण शब्द बनेगा।&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;बल +&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;वान &lt;/span&gt;=&lt;span style=&quot;font-weight: 700; &quot;&gt;&amp;nbsp;&lt;/span&gt;बलवान&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;&amp;#39;बल&amp;#39;&lt;/strong&gt; मूलशब्द और &lt;strong&gt;&amp;#39;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;वान&amp;#39;&amp;nbsp;&lt;/strong&gt;प्रत्यय&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अर्थ-&amp;nbsp;&lt;/strong&gt;शक्तिशाली, पुष्ट,&amp;nbsp;मज़बूत।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;संज्ञा&amp;nbsp;&lt;/span&gt;से बने&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;विशेषण&amp;nbsp;शब्द&lt;/span&gt;&lt;strong&gt;-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;करुणा + &lt;strong&gt;इक&lt;/strong&gt; =&amp;nbsp;&lt;/span&gt;कारुणिक&lt;/li&gt;
	&lt;li&gt;शांति + &lt;strong&gt;पूर्ण&lt;/strong&gt;&amp;nbsp;=&amp;nbsp;शांतिपूर्ण&amp;nbsp;
	&lt;ul&gt;
		&lt;li&gt;श्री + &lt;strong&gt;मान&lt;/strong&gt; =&amp;nbsp;श्रीमान&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;&quot;&gt;श्री +&amp;nbsp;&lt;/span&gt;&lt;strong&gt;मति&lt;/strong&gt; =&amp;nbsp;&lt;span style=&quot;&quot;&gt;श्री&lt;/span&gt;&lt;span style=&quot;&quot;&gt;मति&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संज्ञा&amp;nbsp;शब्द से निर्मित&amp;nbsp;विशेषण शब्द-&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:120px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;संज्ञा&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;विशेषण&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;विष&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;विषैला&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;काया&lt;/span&gt;&lt;span style=&quot; white-space: pre;&quot;&gt; &lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;कायिक&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;आजादी&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;आजाद&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;चमक&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;चमकीला&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;पुराण&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;पौराणिक&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;भारत&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;भारतीय&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ज़हर&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;ज़हरीला&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;अध्यात्म&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;आध्यात्मिक&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;विशेषण-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;&quot;&gt;
	&lt;li&gt;जो शब्द&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;संज्ञा&lt;/span&gt;&amp;nbsp;या&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;सर्वनाम&lt;/span&gt;&amp;nbsp;की&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;विशेषता&lt;/span&gt;&amp;nbsp;(गुण, दोष, संख्या, परिमाण, रंग, आकार, दशा आदि) बतलाए, उसे&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;विशेषण&amp;nbsp;&lt;/span&gt;कहते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;जैसे -&lt;/span&gt;&amp;nbsp;विनम्र, बुद्धिमान,&amp;nbsp;अनुचित, चतुर, झूठा,&amp;nbsp;समान, मोटा,&amp;nbsp;कड़वा, नमकीन,&amp;nbsp;पुराना, ताजा&amp;nbsp;आदि।
	&lt;ul&gt;
		&lt;li&gt;बालक&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;&lt;u&gt;चतुर&lt;/u&gt;&lt;/span&gt;&amp;nbsp;है।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;lsquo;सीता खाना खाकर खेलने गयी&amp;rsquo;- वाक्य में &lt;strong&gt;पूर्वकालिक क्रिया &lt;/strong&gt;का&amp;nbsp; बोध हुआ है। अतः &lt;strong&gt;विकल्प 1&lt;/strong&gt; इसका&amp;nbsp; सही&amp;nbsp; उत्तर है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वाक्य में एक क्रिया तुरंत समाप्त होकर दूसरी क्रिया प्रारंभ हुई है।&lt;/li&gt;
	&lt;li&gt;पहले सीता ने खाना खाया फिर खेलने&amp;nbsp;गयी, वाक्य में दो क्रियाएँ एक साथ हुई।&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;अतः स्पष्ट है कि यहाँ पूर्वकालिक क्रिया का प्रयोग हुआ है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:400px;&quot; width=&quot;400&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:48px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;प&lt;/strong&gt;&lt;strong&gt;ूर्वकालिक क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:352px;&quot;&gt;
			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जो क्रिया एक क्रिया को समाप्त कर तत्काल किसी दूसरी क्रिया को आरम्भ करता है तब पहली क्रिया पूर्णकालिक क्रिया कहलाती है, जैसे- कृष्णा नहाकर स्कूल जाएगा।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;अन्य विकल्प &lt;/strong&gt;&lt;/u&gt;-&amp;nbsp;&amp;nbsp;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:372px;&quot; width=&quot;372&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:91px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:281px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:91px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;संयुक्त क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:281px;&quot;&gt;
			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जो क्रिया दूसरी क्रिया या अन्य शब्द से मिलकर क्रिया बनाती है, उसे संयुक्त क्रिया कहते है।&lt;/p&gt;

			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जैसे - तुम प्रतिदिन व्यायाम किया करो; वह अपना खाना खा चूका है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:91px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;प्रेरणार्थक&amp;nbsp; क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:281px;&quot;&gt;
			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जब कर्ता किसी कार्य को स्वयं न करके किसी दूसरे को कार्य करने की प्रेरणा दे तो उस क्रिया को प्रेरणार्थक क्रिया कहते हैं।&lt;/p&gt;

			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जैसे- काटना से कटवाना, करना से करावाना।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:91px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:3.35pt;&quot;&gt;&lt;strong&gt;सामान्य क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:281px;&quot;&gt;
			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जिस क्रिया में सामान्य रूप से कार्य हो रहा हो वह सामान्य क्रिया कहलाती है।&lt;/p&gt;

			&lt;p style=&quot;margin-left:3.35pt;&quot;&gt;जैसे- राधा नाच रही है;बच्चा दूध पी रहा है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:288px;&quot; width=&quot;287&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:53px;height:22px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;शब्द&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:234px;height:22px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:53px;height:27px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.1pt;&quot;&gt;&lt;strong&gt;क्रिया&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:234px;height:27px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;जिस शब्द अथवा शब्द -समूह के द्वारा किसी कार्य के होने अथवा करने का बोध हो, वह क्रिया कहलाता है।&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.1pt;&quot;&gt;जैसे- देवेश दूध पिता है; अर्चना काम कर रही है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;strong&gt;&amp;#39;अपने सामने&amp;#39;&lt;/strong&gt; कविता संग्रह &amp;quot;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;सर्वेश्वर दयाल सक्सेना&amp;quot;&amp;nbsp;&lt;/strong&gt;द्वारा नहीं लिखा गया है।&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;खूंटियों पर टंगे लोग, काठ की घंटियॉं, कुआनो नदी यह तीनों रचनाऍं&amp;nbsp;सर्वेश्वर दयाल सक्सेना द्वारा लिखी गई&amp;nbsp;है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;1983 में&amp;nbsp;सर्वेश्वर दयाल सक्सेना को उनकी रचना&lt;strong&gt; &amp;#39;खूंटियों पर टंगे लोग&amp;#39; &lt;/strong&gt;के लिए साहित्&amp;zwj;य अकादमी पुरस्&amp;zwj;कार मिला।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;अन्&amp;zwj;य रचनाऍं:-&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:270px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;रचनाकार&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;रचनाऍं&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;सर्वेश्वर दयाल सक्सेना&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;खूँटियों पर टंगे लोग (काव्&amp;zwj;य), पागल कुत्तों का मसीहा (कथा-साहित्य), बकरी (नाटक),&amp;nbsp;बतूता का जूता (बाल कविता), बांस का पुल (काव्&amp;zwj;य), गर्म हवाएं (काव्&amp;zwj;य) आदि।&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;#39;अपने सामने&amp;#39;&lt;/strong&gt; कविता संग्रह कुँवर नारायण द्वारा रचित है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;कुँवर नारायण को वर्ष 2005 में भारत के साहित्य जगत के सर्वोच्च सम्मान&amp;nbsp;ज्ञानपीठ पुरस्कार&amp;nbsp;से सम्मानित किया गया।&lt;/li&gt;
	&lt;li&gt;कुँवर नारायण को वर्ष 1995 में &lt;strong&gt;&amp;#39;आत्&amp;zwj;मजयी&amp;#39; &lt;/strong&gt;(काव्&amp;zwj;य) के लिए व्&amp;zwj;यास सम्&amp;zwj;मान से सम्&amp;zwj;मानित किया गया।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;कुँवर नारायण को वर्ष 1995 में &lt;strong&gt;&amp;#39;कोई दूसरा नहीं&amp;#39;&lt;/strong&gt; के लिए साहित्&amp;zwj;य अकादमी पुरस्&amp;zwj;कार से सम्&amp;zwj;मानित किया गया।&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot; width: 270px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;रचनाकार&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;रचनाऍं&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;कुँवर नारायण&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;चक्रव्यूह (कविता संग्रह), तीसरा सप्तक&amp;nbsp;&lt;span style=&quot;text-align: center; &quot;&gt;(&lt;/span&gt;&lt;span style=&quot;text-align: center; &quot;&gt;कविता संग्रह)&lt;/span&gt;,अपने सामने&lt;span style=&quot;text-align: center; &quot;&gt;&amp;nbsp;(&lt;/span&gt;&lt;span style=&quot;text-align: center; &quot;&gt;कविता संग्रह)&lt;/span&gt;, कोई दूसरा नहीं&amp;nbsp;&lt;span style=&quot;text-align: center; &quot;&gt;(&lt;/span&gt;&lt;span style=&quot;text-align: center; &quot;&gt;कविता संग्रह)&lt;/span&gt;, इन हाशिए के बहाने&lt;span style=&quot;text-align: center; &quot;&gt;&amp;nbsp;(&lt;/span&gt;&lt;span style=&quot;text-align: center; &quot;&gt;कविता संग्रह)&lt;/span&gt;, कविता के बहाने&lt;span style=&quot;text-align: center; &quot;&gt;&amp;nbsp;(&lt;/span&gt;&lt;span style=&quot;text-align: center; &quot;&gt;कविता संग्रह)&lt;/span&gt;, आत्मजयी (खंड काव्य), आदि।&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;सही उत्तर&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); font-weight: 700;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;strong&gt;गुरु - स्तुति, वाणी&lt;/strong&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;#39;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;हैं।&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;#39;गुरु&amp;#39; के&amp;nbsp;अनेकार्थक शब्द&lt;/span&gt;:&amp;nbsp;शिक्षक,&amp;nbsp;श्रद्धेय,&amp;nbsp;ग्रहविशेष, श्रेष्ठ, बृहस्पति,&amp;nbsp;भारी,&amp;nbsp;बड़ा, भार।&lt;/li&gt;
	&lt;li&gt;अन्य सभी विकल्प सुमेलित हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;color: rgb(33, 37, 41); width: 400px;&quot; width=&quot;439&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 73px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;शब्द&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 234px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;परिभाषा&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 132px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 73px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;अनेकार्थी&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;शब्द&lt;/span&gt;&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 234px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;जिन शब्दों के एक से अधिक अर्थ होते हैं, उन्हें &amp;#39;अनेकार्थी शब्द&amp;#39; कहते है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 132px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;काक- कौआ, लँगड़ा आदमी, अतिधृष्ट।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&amp;#39;&lt;span style=&quot;&quot;&gt;ज़&lt;/span&gt;&amp;#39;&lt;/strong&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;हिन्दी में &amp;#39;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;ज़&amp;#39;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;आगत व्यंजन है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;आगत &lt;/strong&gt;व्यंजन- हिंदी मे अंग्रजी और उर्दू भाषा के शब्दों को शुद्ध रूप से लिखने और उचारण के लिए केवल व्यंजन शब्दों में एक बिंदु लगाया जाता है। इसे ही आगत व्यंजन कहते है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;जैसे &lt;/strong&gt;- क़, ख़, ग़, फ़ इत्यादि।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;strong&gt;&lt;strong&gt;अन्य&lt;/strong&gt; &lt;strong&gt;विकल्पों&lt;/strong&gt; &lt;strong&gt;का&lt;/strong&gt; &lt;strong&gt;विश्लेषण&lt;/strong&gt;&lt;strong&gt;:&lt;/strong&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;div data-content-feature=&quot;1&quot;&gt;
&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;दन्त्य &lt;/strong&gt;व्यंजन&amp;nbsp;दन्त्य से उच्चारित होने वाले व्यंजनों को कहा जाता है। जैसे- &lt;strong&gt;त&lt;/strong&gt;, थ, द, ध, न।&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;स्पर्श व्यंजन&lt;/strong&gt;- &lt;strong&gt;च&lt;/strong&gt;, छ, ज, ट, ठ आदि।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संयुक्त &lt;/strong&gt;व्यंजन: दो या दो से अधिक व्यंजनों के मेल से बने होते हैं।&lt;/li&gt;
	&lt;li&gt;चार प्रकार के संयुक्त व्यंजन है - क्ष (क्+ष), त्र(त्+र), ज्ञ (ज्+ञ), श्र (श्+र)।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;समूहवाचक संज्ञा का उदाहरण नहीं है- &lt;strong&gt;&lt;u&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;सैनिक&lt;/span&gt;&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;#39;सैनिक&amp;#39; &lt;/strong&gt;शब्द समूहवाचक संज्ञा का उदाहरण नहीं है,&lt;/li&gt;
	&lt;li&gt;बल्कि &lt;strong&gt;सेना&lt;/strong&gt; शब्द ही &lt;strong&gt;सैनिकों के समूह&lt;/strong&gt; के लिए&lt;strong&gt; समूहवाचक संज्ञा &lt;/strong&gt;है&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;&amp;#39;​&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;सैनिक&lt;/span&gt;&amp;#39;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt; &lt;strong&gt;जातिवाचक संज्ञा&lt;/strong&gt; है क्योंकि यह शब्द &lt;strong&gt;सैनिक जाति का&lt;/strong&gt; बोध कराता है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt;जो शब्द किसी &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;व्यक्ति, वस्तु&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; या &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;स्थान&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; की &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;संपूर्ण जाति का बोध &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt;कराते हैं, उन शब्दों को &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;जातिवाचक संज्ञा&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; कहते हैं।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt;​&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;जैसे- &lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt;मोबाइल, टीवी, &lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt;गाँव, स्कूल, शहर, बगीचा, नदी, जानवर, पशु, पक्षी, गाय, लड़का आदि।&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;&lt;u&gt;पेड़ों&lt;/u&gt;&lt;/strong&gt; पर &lt;strong&gt;&lt;u&gt;पक्षी&lt;/u&gt;&lt;/strong&gt; बैठे हैं।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;u&gt;कुत्ता&lt;/u&gt;&lt;/strong&gt; एक वफादार &lt;strong&gt;&lt;u&gt;जानवर&lt;/u&gt;&lt;/strong&gt; होता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:340px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संज्ञा&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;परिभाषा &lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;उदाहरण&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;व्यक्तिवाचक&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); white-space: pre;&quot;&gt; &lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt;किसी भी विशेष&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt; व्यक्ति, वस्तु&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; या &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;स्थान&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; के नाम का बोध कराने वाली संज्ञा ही &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;व्यक्तिवाचक संज्ञा&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt; कहलाती हैं। &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center; font-weight: bolder;&quot;&gt;जैसे- &lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41); text-align: center;&quot;&gt;महात्मा गाँधी, भगत सिंह, रमेश, रामायण, बाइबल, दिल्ली, मुंबई, लखनऊ आदि।&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;मैं &lt;strong&gt;&lt;u&gt;बेंगलुरु&lt;/u&gt;&lt;/strong&gt; में रहता हूँ।&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;भाववाचक&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;
			&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;जो शब्द किसी &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;चीज़&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; या &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;पदार्थ&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; की&lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt; अवस्था, दशा&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; या &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;भाव&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; का बोध कराते हैं, उन शब्दों को &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;भाववाचक संज्ञा&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; कहते हैं। &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;जैसे-&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; बचपन, बुढ़ापा, मोटापा, मिठास, उमंग, चढाई, थकावट, मानवता, चतुराई, जवानी, लम्बाई, मित्रता, मुस्कुराहट, अपनापन, भूख, आदि। &lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;भारत में &lt;strong&gt;&lt;u&gt;गरीबी&lt;/u&gt;&lt;/strong&gt; बढ़ रही है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;समूहवाचक&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;
			&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;जिन &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;संज्ञा&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; शब्दों से किसी भी व्यक्ति या &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;वस्तु के समूह&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; का बोध होता है, &lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt;उन शब्दों को &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;समूहवाचक &lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt;या &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;समुदायवाचक संज्ञा&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; कहते हैं। &lt;/span&gt;&lt;span style=&quot;text-align: center; font-weight: bolder;&quot;&gt;जैसे-&lt;/span&gt;&lt;span style=&quot;text-align: center;&quot;&gt; भीड़, मेला, सभा, कक्षा, परिवार, पुस्तकालय, झुंड, गिरोह, सेना, दल, गुच्छा, दल, टुकड़ी आदि।&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;आज तुम्हारी &lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;u&gt;कक्षा&lt;/u&gt;&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt; नही चलेगी।&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;द्रव्यवाचक&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;जो शब्द किसी &lt;span style=&quot;font-weight: bolder;&quot;&gt;ठोस, तरल, पदार्थ, धातु, अधातु &lt;/span&gt;या &lt;span style=&quot;font-weight: bolder;&quot;&gt;द्रव्य&lt;/span&gt; का बोध करते हैं, &lt;span style=&quot;font-weight: bolder;&quot;&gt;द्रव्यवाचक संज्ञा &lt;/span&gt;कहलाते हैं। &lt;span style=&quot;font-weight: bolder;&quot;&gt;जैसे- &lt;/span&gt;कोयला, पानी, तेल, घी, लोहा, सोना, चांदी, हीरा, चीनी, फल, सब्ज़ी आदि द्रव्य हैं।&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;​&lt;/span&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;मुझे &lt;strong&gt;&lt;u&gt;सोने&lt;/u&gt;&lt;/strong&gt; का हार खरीदना है।&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;संज्ञा-&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;किसी भी &lt;span style=&quot;font-weight: bolder;&quot;&gt;व्यक्ति, वस्तु, जाति, भाव &lt;/span&gt;या &lt;span style=&quot;font-weight: bolder;&quot;&gt;स्थान&lt;/span&gt; के नाम को &lt;span style=&quot;font-weight: bolder;&quot;&gt;संज्ञा &lt;/span&gt;कहते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;जैसे - &lt;/span&gt;मनुष्य (जाति), भारत (स्थान), बचपन (भाव), टेबल (वस्तु) आदि।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color:  (33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;संज्ञा के भेद -&lt;/span&gt;&lt;/p&gt;

&lt;ol style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;व्यक्तिवाचक संज्ञा&lt;/li&gt;
	&lt;li&gt;जातिवाचक संज्ञा&lt;/li&gt;
	&lt;li&gt;भाववाचक संज्ञा&lt;/li&gt;
	&lt;li&gt;समुदाय या समूहवाचक संज्ञा&lt;/li&gt;
	&lt;li&gt;द्रव्यवाचक संज्ञा&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;सही उत्तर&amp;nbsp;&lt;strong&gt;&amp;#39;शाक&amp;#39;&amp;nbsp;&lt;/strong&gt;हैं।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;दिए गए विकल्पों में&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&lt;span style=&quot;&quot;&gt;तद्भव शब्द &amp;#39;&lt;strong&gt;साग&lt;/strong&gt;&amp;#39; का तत्सम रूप&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;शाक&lt;/span&gt; है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;सब्जी&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;margin: 0px; padding: 0px; line-height: inherit; -webkit-font-smoothing: antialiased; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-weight: 700; font-stretch: inherit;  vertical-align: baseline; &quot;&gt;फारसी&amp;nbsp;शब्द&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;&quot;&gt;भाजी&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: bold;  &quot;&gt;देशज&amp;nbsp;&lt;/span&gt;&lt;span style=&quot; margin: 0px; padding: 0px; line-height: inherit; -webkit-font-smoothing: antialiased; border: 0px; font-variant-numeric: inherit; font-variant-east-asian: inherit; font-weight: 700; font-stretch: inherit; vertical-align: baseline;&quot;&gt;शब्द&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;है।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:370px;&quot; width=&quot;555&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;शब्द&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;परिभाषा&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;उदहारण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;strong&gt;तत्सम&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;हिंदी में वह शब्द जो संस्कृत से सीधे आ गए है और आज भी प्रयोग हो रहे है उसे तत्सम शब्द कहते है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;वायु,&amp;nbsp; सूर्य&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;तद्भव&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;संस्कृत शब्दों से परिवर्तित हो कर बने शब्द। ऐसे शब्द जिनका जनम संस्कृत से हुआ है। परन्तु समाये क साथ बोलते बोलते उनका स्वरुप बदल गया है उसे तद्भव शब्द कहते है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;सीख, काठ&amp;nbsp;&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;देशज&amp;nbsp;&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;वे शब्द जिनकी उत्पत्ति के मूल का पता न हो परन्तु वे प्रचलन में हो, ऐसे शब्द देशज शब्द कहलाते हैं। ये शब्द आम तौर पर क्षेत्रीय भाषा में प्रयोग किये जाते हैं।&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;लोटा, कटोरा, डोंगा, डिबिया, खिचड़ी, खिड़की, पगड़ी, ठुमरी, तेंदुआ आदि।&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;विदेशी शब्द&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;विदेशी भाषाओं से हिंदी में आये शब्दों को विदेशी शब्द कहा जाता है। इन विदेशी भाषाओं में मुख्यतः अरबी, फारसी, तुर्की, अंग्रेजी व पुर्तगाली शामिल है।&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;आदमी, बहादुर, आलमारी, अफ़सोस, इंजन, डॉक्टर आदि।&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/u&gt;कुछ&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;महत्वपूर्ण&lt;/strong&gt;&amp;nbsp;&amp;nbsp;&lt;strong&gt;तत्सम&lt;/strong&gt;&lt;strong&gt;- &lt;/strong&gt;&lt;strong&gt;तद्भव&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;शब्द&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;तद्भव&amp;nbsp;शब्द&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;तत्सम&amp;nbsp;शब्द&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;अकथ&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;अकथ्य&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;अकाज&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;अकार्य&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;अकेला&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;एकल&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;क्यों&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;किंपुनः&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;खंडहर&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;खण्डगृह&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;खत्री&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;क्षत्रिय&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;नींबू&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;निम्बक&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;नीम&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;निम्ब&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;सही उत्तर है - &amp;ldquo;&lt;strong&gt;मुख्य - विमुख&lt;/strong&gt;&amp;rdquo;।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;उपर्युक्त विकल्पों में से विकल्प &amp;lsquo;&lt;strong&gt;मुख्य - विमुख&lt;/strong&gt;&amp;rsquo; सही विलोम शब्द &lt;strong&gt;&lt;u&gt;युग्म नहीं&lt;/u&gt;&lt;/strong&gt; है।&lt;/li&gt;
	&lt;li&gt;अन्य विकल्प इसके सही &lt;strong&gt;विलोम युग्म&lt;/strong&gt; हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मुख्य&amp;nbsp;&lt;/strong&gt;का विलोम शब्द &lt;strong&gt;गौण &lt;/strong&gt;होता है।&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;अतः&lt;strong&gt; मुख्य&amp;nbsp;- गौण&amp;nbsp;&lt;/strong&gt;सही विलोम युग्म बनता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मुख्य&amp;nbsp;का अर्थ है &lt;/strong&gt;- सबसे ऊपर या बड़ा, प्रमुख, सर्वोच्च।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;गौण&lt;/strong&gt;&amp;nbsp;&lt;strong&gt;का अर्थ &lt;/strong&gt;- अप्रधान, जो मूल अर्थ से भिन्न हो।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विमुख&lt;/strong&gt; &lt;strong&gt;का अर्थ &lt;/strong&gt;- विरत, प्रतिकूल।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;अन्य विकल्प:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;मुख&amp;nbsp;&lt;/strong&gt;का अर्थ -सामने, सम्मुख&amp;nbsp;&lt;br /&gt;
	&lt;strong&gt;पृष्ठ&amp;nbsp;&lt;/strong&gt;का&lt;strong&gt; &lt;/strong&gt;अर्थ - पदार्थ आदि के पीछे का भाग, पीठ।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मिथ्या&amp;nbsp;&lt;/strong&gt;का अर्थ - असत्य, झूठा।&lt;br /&gt;
	&lt;strong&gt;सत्य&amp;nbsp;&lt;/strong&gt;का अर्थ - सच, यथातथ्य।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मुक्त&amp;nbsp;&lt;/strong&gt;का अर्थ - स्वतंत्र, आज़ाद, छूटा हुआ।&amp;nbsp;&lt;br /&gt;
	&lt;strong&gt;बद्ध&amp;nbsp;&lt;/strong&gt;का अर्थ - बँधा हुआ, भव बंधन में फँसा हुआ।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;विलोम शब्द&lt;/strong&gt; अर्थात किसी शब्द के अर्थ के विपरीत अर्थ वाला शब्द उस शब्द का &lt;strong&gt;विलोम शब्द&lt;/strong&gt; कहलाता है।&lt;/li&gt;
	&lt;li&gt;विलोम शब्द को आप विपरीतार्थक शब्द या विरुद्धार्थी शब्द व उल्टा शब्द भी कह सकते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;उदाहरण &lt;/strong&gt;&amp;ndash; दिन का विलोम शब्द रात होता है। इसमें दिन रात के विपरीत हैं तो दिन और रात एक दूसरे के विलोम शब्द कहलायेंगे।&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;strong&gt;&amp;nbsp;कुछ महत्वपूर्ण विलोम शब्द:-&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;कटु -&lt;span style=&quot;white-space:pre&quot;&gt; &lt;/span&gt;मधु&lt;/li&gt;
	&lt;li&gt;क्रूर&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;अक्रूर&lt;/li&gt;
	&lt;li&gt;कृत्रिम&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;प्रकृत&lt;/li&gt;
	&lt;li&gt;कपटी&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;निष्कपट&lt;/li&gt;
	&lt;li&gt;कुटिल&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;सरल&lt;/li&gt;
	&lt;li&gt;क्रोध&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;क्षमा&lt;/li&gt;
	&lt;li&gt;कर्मण्य&lt;span style=&quot;white-space:pre&quot;&gt; - &lt;/span&gt;अकर्मण्य&lt;/li&gt;
	&lt;li&gt;कोप&lt;span style=&quot;white-space: pre;&quot;&gt; - &lt;/span&gt;कृपा&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;lsquo;थोड़ा&amp;rsquo; शब्द &amp;lsquo;परिमाणवाचक&amp;nbsp;विशेषण&amp;rsquo; का उदाहरण है। अतः इसका सही उत्तर &lt;strong&gt;विकल्प&lt;/strong&gt;&lt;strong&gt; 1 &lt;/strong&gt;&lt;strong&gt;&amp;lsquo;&lt;/strong&gt;&lt;strong&gt;परिमाणवाचक&lt;/strong&gt; &lt;strong&gt;विशेषण&lt;/strong&gt;&lt;strong&gt;&amp;rsquo;&lt;/strong&gt; होगा। अन्य विकल्प सही उत्तर नहीं हैं।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:103px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;परिमाणवाचक विशेषण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:354px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;ऐसे शब्द जो संज्ञा या सर्वनाम की मात्रा का बोध कराते हैं।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:181px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;चार किलो, एक मीटर, दो लीटर, थोड़ा, बहुत आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;अन्य&lt;/strong&gt; &lt;strong&gt;विकल्प&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:97px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;संख्यावाचक विशेषण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:337px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;ऐसे शब्द जो संज्ञा या सर्वनाम की संख्या का बोध कराते हैं।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;दो, तीनों, चार गुना, प्रत्येक आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:97px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;गुणवाचक विशेषण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:337px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;वे शब्द जो संज्ञा या सर्वनाम के गुण, धर्म, स्वाभाव आदि का बोध कराये।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;बलशाली, पुराण, नया, तीक्ष्ण, कमजोर, मोटा, दुर्बल, पठारी आदि।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:97px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;सार्वनामिक विशेषण&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:337px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;वे सर्वनाम शब्द जो संज्ञा से पहले आयें और विशेषण की तरह उस संज्ञा शब्द की विशेषता बताएं।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:189px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;यह लड़की वही है जिसने मेरा पेन लिया था।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;2&quot; style=&quot;width:638px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;विशेषण&lt;/strong&gt; - जो शब्द संज्ञा या सर्वनाम शब्दों की विशेषता बताते हैं। इसके मुख्यतः आठ भेद हैं -&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;गुणवाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;व्यक्तिवाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;संख्यावाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;प्रश्नवाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;परिमाणवाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;तुलनाबोधक विशेषण&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;सार्वनामिक विशेषण&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:319px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;सम्बन्धवाचक विशेषण&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;
